// ── Servlet (Controller) puts data in request scope ──────────────────
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.*;
import java.io.*;
import java.util.*;

@WebServlet("/products")
public class ProductServlet extends HttpServlet {

    // Simulated product data (real app: from service layer)
    record Product(int id, String name, double price, String category, boolean inStock) {}

    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse res)
            throws Exception {

        List<Product> products = List.of(
            new Product(1, "Laptop",    999.99, "Electronics", true),
            new Product(2, "Keyboard",   79.99, "Electronics", true),
            new Product(3, "Desk Chair",349.00, "Furniture",   false),
            new Product(4, "Monitor",   299.99, "Electronics", true),
            new Product(5, "USB Hub",    24.99, "Electronics", false)
        );

        // Filter by category if query param present
        String cat = req.getParameter("category");
        List<Product> filtered = (cat != null && !cat.isEmpty())
            ? products.stream().filter(p -> p.category().equals(cat)).toList()
            : products;

        // Put data in REQUEST scope — available in JSP as ${products}
        req.setAttribute("products",   filtered);
        req.setAttribute("totalCount", filtered.size());
        req.setAttribute("category",   cat != null ? cat : "All");

        // Forward to JSP view (NOT redirect — shares the same request)
        req.getRequestDispatcher("/WEB-INF/views/products.jsp").forward(req, res);
    }
}

