// Demonstrate key EL features separately:
public class ELDemo {
    public static void main(String[] args) {
        System.out.println("EL scope search order (narrowest first):");
        System.out.println("page → request → session → application");
        System.out.println();
        System.out.println("EL implicit objects:");
        System.out.println("${param.name}           → request.getParameter('name')");
        System.out.println("${sessionScope.user}    → session.getAttribute('user')");
        System.out.println("${requestScope.items}   → request.getAttribute('items')");
        System.out.println("${applicationScope.cfg} → context.getAttribute('cfg')");
        System.out.println("${header['User-Agent']} → request.getHeader('User-Agent')");
        System.out.println();
        System.out.println("EL operations:");
        System.out.println("${price > 100}   arithmetic/comparison");
        System.out.println("${empty list}    null or empty check");
        System.out.println("${a ? b : c}     ternary");
        System.out.println("${map['key']}    map access");
        System.out.println("${list[0].name}  indexed access + property chain");
    }
}

/**
 * Understanding JSP compilation helps debug 'cannot find symbol' errors
 * and '500 Internal Server Error' from JSP parse failures.
 */

// What Tomcat generates from hello.jsp:
// <%@ page contentType="text/html;charset=UTF-8" %>
// <html><body>
// <% String name = request.getParameter("name"); %>
// <h1>Hello, <%= name %>!</h1>
// </body></html>

// Tomcat translates to this (simplified):
import jakarta.servlet.*;
import jakarta.servlet.http.*;
import jakarta.servlet.jsp.*;

// Generated class — extends HttpJspBase which extends HttpServlet
public final class hello_jsp extends org.apache.jasper.runtime.HttpJspBase {

    @Override
    public void _jspInit() {
        // init() equivalent for JSP — called once
        System.out.println("JSP initialized");
    }

    @Override
    public void _jspDestroy() {
        // destroy() equivalent
    }

    @Override
    public void _jspService(HttpServletRequest request,
                            HttpServletResponse response)
            throws java.io.IOException, ServletException {

        // Implicit objects injected by the container:
        PageContext     pageContext = null;                  // manages all scopes
        HttpSession     session     = null;                  // available unless <%@ page session='false' %>
        ServletContext  application = null;                  // app-wide scope
        ServletConfig   config      = null;
        JspWriter       out         = null;                  // like PrintWriter
        Object          page        = this;

        response.setContentType("text/html;charset=UTF-8");

        pageContext = JspFactory.getDefaultFactory()
            .getPageContext(this, request, response, null, true, 8192, true);
        application = pageContext.getServletContext();
        config      = pageContext.getServletConfig();
        session     = pageContext.getSession();
        out         = pageContext.getOut();

        // ── Translation of JSP source ──────────────────────────────────
        // <html><body>  → literal output
        out.write("<html><body>\n");

        // <% String name = request.getParameter("name"); %>  → scriptlet
        String name = request.getParameter("name");

        // <h1>Hello, <%= name %>!</h1>  → expression
        out.write("<h1>Hello, ");
        out.print(name);          // <%= %> becomes out.print()
        out.write("!</h1>\n</body></html>");
    }
}

public class JSPLifecycleDemo {
    public static void main(String[] args) {
        System.out.println("JSP Translation phases:");
        System.out.println("1. Translation: .jsp → .java (by Jasper/Tomcat)");
        System.out.println("2. Compilation: .java → .class");
        System.out.println("3. Loading:     ClassLoader loads the servlet class");
        System.out.println("4. Instantiation: new hello_jsp()");
        System.out.println("5. _jspInit():    runs once");
        System.out.println("6. _jspService(): runs per request (concurrent threads)");
        System.out.println("7. _jspDestroy(): runs once on undeploy/reload");
        System.out.println();
        System.out.println("Key debugging facts:");
        System.out.println("- First request is slow: compilation happens then");
        System.out.println("- EL disabled in JSP 2.0+? Check web.xml: isELIgnored=false");
        System.out.println("- 500 error on JSP? Check catalina.out for Java compile error");
        System.out.println("- Scriptlet error line != JSP line: check generated .java file");
        System.out.println("  (Tomcat: work/Catalina/localhost/app/org/apache/jsp/)");
        System.out.println();
        System.out.println("Implicit objects available WITHOUT declaration:");
        System.out.println("request, response, session, application, out,");
        System.out.println("config, page, pageContext, exception (error pages only)");
    }
}

