public class Q1 {
    public static void main(String[] args) {
        System.out.println("EL scope search order (narrowest first):");
        System.out.println("1. page (pageContext) → 2. request → 3. session → 4. application");
        System.out.println();
        System.out.println("Scenario 1: request='Alice', session='Bob'");
        System.out.println("${user} resolves to: 'Alice'");
        System.out.println("  (request is narrower than session, found first)");
        System.out.println();
        System.out.println("Scenario 2: page='Charlie', request='Alice', session='Bob'");
        System.out.println("${user} resolves to: 'Charlie'");
        System.out.println("  (page scope is narrowest, searched first)");
        System.out.println();
        System.out.println("Explicit scope targeting:");
        System.out.println("${requestScope.user}     → always reads from request scope");
        System.out.println("${sessionScope.user}     → always reads from session scope");
        System.out.println("${applicationScope.cfg}  → always reads from application scope");
        System.out.println("${pageScope.user}        → always reads from page scope");
        System.out.println();
        System.out.println("Best practice: use explicit scope in EL to avoid surprises");
    }
}

