import java.util.*;

public class Q2 {
    record Student(String name, double grade, boolean passed) {}

    public static void main(String[] args) {
        List<Student> students = List.of(
            new Student("Alice",   92.5, true),
            new Student("Bob",     58.0, false),
            new Student("Charlie", 75.3, true),
            new Student("Diana",   41.8, false),
            new Student("Eve",     88.9, true)
        );

        System.out.println("JSTL JSP code:");
        System.out.println("<%@ taglib prefix='c'   uri='http://java.sun.com/jsp/jstl/core' %>");
        System.out.println("<%@ taglib prefix='fmt' uri='http://java.sun.com/jsp/jstl/fmt' %>");
        System.out.println("<table>");
        System.out.println("<c:forEach items='${students}' var='s' varStatus='st'>");
        System.out.println("  <tr style='background:${st.index % 2 == 0 ? '#f0f0f0' : 'white'}'>");
        System.out.println("    <td>${st.count}</td>");
        System.out.println("    <td>${s.name}</td>");
        System.out.println("    <td><fmt:formatNumber value='${s.grade}' maxFractionDigits='0'/></td>");
        System.out.println("    <td>");
        System.out.println("      <c:choose>");
        System.out.println("        <c:when test='${s.passed}'><span style='color:green'>PASS</span></c:when>");
        System.out.println("        <c:otherwise><span style='color:red'>FAIL</span></c:otherwise>");
        System.out.println("      </c:choose>");
        System.out.println("    </td>");
        System.out.println("  </tr>");
        System.out.println("</c:forEach>");
        System.out.println("</table>");
        System.out.println();
        System.out.println("varStatus properties: count(1-based), index(0-based), first, last, step");
        System.out.println();
        System.out.println("Expected output:");
        System.out.println("Row | Name    | Grade | Status");
        for (int i = 0; i < students.size(); i++) {
            Student s = students.get(i);
            System.out.printf("%-3d | %-7s | %-5.0f | %s%n",
                i+1, s.name(), s.grade(), s.passed() ? "PASS" : "FAIL");
        }
    }
}
